import{_ as i,C as s,o as n,c as l,j as e,a as d,E as r,ag as o}from"./chunks/framework.DLWhSH9p.js";const w=JSON.parse('{"title":"Scripts","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scripts.md","filePath":"guide/scripts.md"}'),h={name:"guide/scripts.md"};function c(g,t,p,u,m,b){const a=s("SchemeImage");return n(),l("div",null,[t[0]||(t[0]=e("h1",{id:"scripts",tabindex:"-1"},[d("Scripts "),e("a",{class:"header-anchor",href:"#scripts","aria-label":'Permalink to "Scripts"'},"​")],-1)),t[1]||(t[1]=e("p",null,"The Script Editor is where ideas become content. AI writes, revises, and polishes scripts in your character's voice, with fact-checking and humanization tools.",-1)),r(a,{name:"script-editor",alt:"Script Editor — three-column Flow layout"}),t[2]||(t[2]=o('<h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>The editor is a three-column grid:</p><ul><li><strong>Left — script list rail.</strong> Every script in the channel, one row each with title, status badge (draft / review / final), and word count. Click to jump between scripts — unsaved work is committed first.</li><li><strong>Centre — editor.</strong> Sticky toolbar at the top, a giant serif title input, then the script body (JetBrains Mono, 15px). Stage directions and dialog render inline. Fact-check highlights overlay the text when a check is active.</li><li><strong>Right — AI copilot rail.</strong> Four tabs — <strong>Revise</strong>, <strong>Facts</strong>, <strong>Humanize</strong>, <strong>Pacing</strong> — plus a <strong>Pipeline Spine</strong> at the bottom that shows where this script sits in the Idea → Script → Audio → Episode → Publish arc.</li></ul><h2 id="toolbar" tabindex="-1">Toolbar <a class="header-anchor" href="#toolbar" aria-label="Permalink to &quot;Toolbar&quot;">​</a></h2><p>The sticky toolbar at the top of the editor holds:</p><ul><li><strong>Status badge</strong> — draft / review / final, colour-coded</li><li><strong>Type badge</strong> — short or long</li><li><strong>Word count</strong> — spoken words only, with a progress bar toward the target (150 for Shorts, 1500 for Long-form)</li><li><strong>Auto-save indicator</strong> — <code>saving…</code> / <code>unsaved</code> / <code>auto-saved · 14s</code></li><li><strong>Status dropdown</strong> — promote draft → review → final</li><li><strong>Fact check / Humanize</strong> buttons</li><li><strong>Send to audio</strong> (on review/final) or <strong>Promote &amp; send</strong> (from draft — sets status to review and jumps straight to the Audio room)</li><li><strong>Save</strong>* button when there are unsaved changes</li></ul><h2 id="ai-writing-—-the-revise-tab" tabindex="-1">AI writing — the Revise tab <a class="header-anchor" href="#ai-writing-—-the-revise-tab" aria-label="Permalink to &quot;AI writing — the Revise tab&quot;">​</a></h2><p>The <strong>Revise</strong> tab in the right rail holds all generation controls:</p><table tabindex="0"><thead><tr><th>Button</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Write with voice</strong></td><td>Generates a full script in your channel&#39;s character voice from the title and any existing content</td></tr><tr><td><strong>Revise</strong></td><td>Expands a textarea — type what to change (&quot;make the intro punchier&quot;, &quot;add more technical detail&quot;), press <strong>Go</strong></td></tr></tbody></table><p>Under those is a <strong>Related</strong> section with a shortcut to open the <a href="/guide/resources.html">Resource Search</a> panel for adding reference material.</p><div class="tip custom-block"><p class="custom-block-title">Shorts get special treatment</p><p>Scripts marked <strong>Short</strong> are generated with a seamless loop — the last sentence trails off incomplete and the first sentence completes it, so the video loops cleanly. No hashtags in the content (they&#39;re extracted to tags automatically).</p></div><h2 id="fact-check" tabindex="-1">Fact check <a class="header-anchor" href="#fact-check" aria-label="Permalink to &quot;Fact check&quot;">​</a></h2>',12)),r(a,{name:"fact-check",alt:"Fact Check Panel"}),t[3]||(t[3]=o('<p>Click <strong>Fact check</strong> in the toolbar. The Facts tab lights up in the right rail and the editor body gets inline highlights that follow the classification:</p><ul><li><strong>Verified</strong> (green) — confirmed accurate</li><li><strong>Unverified</strong> (amber) — plausible but not confirmed</li><li><strong>Disputed</strong> (red) — contradicts known facts</li><li><strong>Opinion</strong> (blue) — subjective, not a factual claim</li></ul><p>Click any claim in the Facts panel to jump the editor cursor to that passage. Claims that don&#39;t match any text in the script appear under <strong>Summary claims</strong> — they&#39;re the AI&#39;s higher-level observations.</p><h2 id="humanize" tabindex="-1">Humanize <a class="header-anchor" href="#humanize" aria-label="Permalink to &quot;Humanize&quot;">​</a></h2><p>Click <strong>Humanize</strong> in the toolbar. The Humanize tab shows each detected passage:</p><ul><li><strong>Fixed</strong> (green) — auto-rewritten; shows original with strikethrough + rewrite in info-blue</li><li><strong>Flagged</strong> (amber) — needs manual judgment</li></ul><p>Use <strong>Apply all fixes</strong> for a wholesale rewrite, or <strong>Apply this fix</strong> on a single passage. Click any passage header to jump into the editor at that line.</p><h2 id="pacing-tab" tabindex="-1">Pacing tab <a class="header-anchor" href="#pacing-tab" aria-label="Permalink to &quot;Pacing tab&quot;">​</a></h2><p>Switch to <strong>Pacing</strong> for a read-only breakdown:</p><ul><li>Large serif word count vs. target with a progress bar</li><li>Estimated read time at 150 wpm</li><li>Structure — paragraphs, stage directions, average words per paragraph</li><li>Section sizes — one bar per paragraph, longest normalised</li></ul><p>Useful for spotting pacing problems (e.g. a 400-word dump that needs splitting, or a dozen 20-word graphs that read like twitter).</p><h2 id="pipeline-spine" tabindex="-1">Pipeline Spine <a class="header-anchor" href="#pipeline-spine" aria-label="Permalink to &quot;Pipeline Spine&quot;">​</a></h2><p>The bottom of the AI rail shows the five-step arc: <code>Idea → Script [here] → Audio → Episode → Publish</code>. It tells you at a glance what&#39;s upstream (what the script was derived from) and what&#39;s unblocked for the next stage (e.g. Audio lights up once status is review/final).</p><h2 id="status-workflow" tabindex="-1">Status workflow <a class="header-anchor" href="#status-workflow" aria-label="Permalink to &quot;Status workflow&quot;">​</a></h2><p>Scripts progress through three statuses via the dropdown in the toolbar:</p><table tabindex="0"><thead><tr><th>Status</th><th>Meaning</th><th>Audio</th></tr></thead><tbody><tr><td><strong>Draft</strong></td><td>Work in progress</td><td>Blocked</td></tr><tr><td><strong>Review</strong></td><td>Ready for review</td><td>Allowed</td></tr><tr><td><strong>Final</strong></td><td>Production ready</td><td>Allowed</td></tr></tbody></table><p>The <strong>Storyboard</strong> editor under Episodes prefers review/final scripts too — once the script&#39;s there, the storyboard row on the episode lights up an <strong>Open editor</strong> action. See <a href="/guide/storyboard.html">Storyboard</a>.</p><h2 id="auto-save" tabindex="-1">Auto-save <a class="header-anchor" href="#auto-save" aria-label="Permalink to &quot;Auto-save&quot;">​</a></h2><p>Scripts auto-save every 30 seconds when modified. The indicator in the toolbar shows <code>unsaved</code> when there are pending edits and counts up seconds since the last save when clean.</p>',19))])}const v=i(h,[["render",c]]);export{w as __pageData,v as default};
